// AGENT: Scam Detection v1.0.0 — PLACEHOLDER
// In Phase 4, uses Claude Haiku with pattern detection:
//  - Upfront payment requests → scam_score += 50
//  - Unrealistic salary + minimal requirements → scam_score += 30
//  - Non-professional email domains in description → scam_score += 20

const input = $input.first().json;
const ctx   = input.execution_context;
if (!ctx) throw new Error('[scam_detection] Missing execution_context');

const started_at = Date.now();
const listings   = ctx.results.jobs_quality_scored || ctx.results.jobs_merged || [];
console.log(`[scam_detection] START | listings=${listings.length}`);

// PLACEHOLDER: Score all listings at scam_score=0 (none are scams)
const scam_scores = listings.map(l => ({
  listing_id:   l.listing_id,
  scam_score:   0,
  is_scam:      false,
  scam_signals: []
}));

const duration_ms = Date.now() - started_at;
console.log(`[scam_detection] COMPLETE (placeholder) | scams=0 / ${listings.length}`);

return [{
  json: {
    execution_context: ctx,
    filter_type:       'scam',
    scam_scores,
    status:            'placeholder',
    agent_meta: { agent_id: 'agent-scam-detection', agent_version: '1.0.0', execution_id: ctx.execution_id, model_used: null, tokens_total: 0, duration_ms, status: 'placeholder', error: null }
  }
}];
